//초기화
scwin.btn_fieldClear_onclick = function (e) {
  $c.gus.cfInitObjects($p, tb_searchCondition, null);
  ds_BulkTariff.removeAll();
  scwin.f_DefaultValue();
};
scwin.onUdcCompleted = function () {
  scwin.f_DefaultValue();
  cnd_ed_tCust.focus();
};
scwin.f_DefaultValue = function () {
  scwin.f_Set("INIT");
};
scwin.f_Set = function (gubun) {
  //console.log("gubun : " + gubun);
  switch (gubun) {
    case "INIT":
      //초기화
      $c.gus.cfDisableBtn($p, [btn_cancel, btn_save]);
      $c.gus.cfEnableBtnOnly($p, [btn_create]);
      $c.gus.cfDisableBtnOnly($p, [btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
      scwin.statusFlag = "INIT";
      break;
    case "RETRIEVE":
      //조회모드
      $c.gus.cfEnableBtnOnly($p, [btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
      $c.gus.cfDisableBtnOnly($p, [btn_cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_save, btn_create]);
      scwin.statusFlag = "RETRIEVE";
      break;
    case "CREATE":
      //신규
      $c.gus.cfDisableBtnOnly($p, [btn_create, btn_save]);
      $c.gus.cfEnableBtnOnly($p, [btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
      $c.gus.cfEnableBtnOnly($p, [btn_cancel, btn_save]);
      scwin.statusFlag = "CREATE";
      break;
    case "UPDATE":
      //수정
      scwin.statusFlag = "UPDATE";
      break;
    case "SAVE":
      //저장
      cfEnableBtnOnly([btn_save]);
      scwin.statusFlag = "SAVE";
      break;
    case "DELETE":
      //삭제
      break;
  }
};

