// 계약번호 조회
scwin.f_ContractInfo = function () {
  //계약번호 조회전 데이터셋에 들어간 계약번호를 공백 처리한다
  ds_BulkTariff.setCellData(ds_BulkTariff.getRowPosition(), "contractno", "");
  ds_BulkTariff.setCellData(ds_BulkTariff.getRowPosition(), "apdtFrom", "");
  ds_BulkTariff.setCellData(ds_BulkTariff.getRowPosition(), "apdtTo", "");

  //ds_ctrtNo.removeAll();

  let cust = ds_BulkTariff.getCellData(ds_BulkTariff.getRowPosition(), "cust");
  if (dma_retrieveCtrtClnt.get("ctrtClntNo") == cust) {
    //조회된 계약번호의 거래처번호와 현재 그리드에 입력된 거래처번호가 다를 경우에만 계약번호를 조회한다.
    return;
  }
  if (scwin.hasCtrtNo(cust)) {
    //이미 받아온적이 있는 거래처이면 새로 받지 않고 필터만 조절하여 표시한다.
    scwin.updateCtrnNoFilter(cust);
    return;
  }
  dma_retrieveCtrtClnt.set("ctrtClntNo", cust);
  dma_retrieveCtrtClnt.set("bizDivBulkYn", "1");
  dma_retrieveCtrtClnt.set("ctrtDistrictCd", "ZZA");
  $c.sbm.execute($p, sbm_retrieveCtrtClnt);
};
scwin.sbm_retrieveCtrtClnt_submitdone = function () {
  let data = ds_ctrtNoTemp.getAllJSON();
  let ctrtClntNo = ds_BulkTariff.getCellData(ds_BulkTariff.getRowPosition(), "cust");

  //data에 ctrtNo 가  '선택' 으로 나오는 것은 필요없으니 제거한다.
  data = data.filter(function (item) {
    return item.ctrtNo != '선택';
  });

  //필터조건을 위해 계약번호(ctrtClntNo)를 추가하여 저장한다.
  data.forEach(element => {
    element.ctrtClntNo = ctrtClntNo;
  });
  ds_ctrtNo.setJSON(data, true);
  let selectedCust = ds_BulkTariff.getCellData(ds_BulkTariff.getRowPosition(), "cust");
  scwin.updateCtrnNoFilter(selectedCust);
  let value = ds_BulkTariff.getCellData(ds_BulkTariff.getRowPosition(), "contractno");
  //계약번호 재조회
  if (ds_BulkTariff.getRowStatus(ds_BulkTariff.getRowPosition()) == "C") {
    //신규

    ds_BulkTariff.setCellData(ds_BulkTariff.getRowPosition(), "contractno", value);
  }
};
scwin.hasCtrtNo = function (cust) {
  let hasData = false;
  for (let i = 0; i < ds_ctrtNo.getRowCount(); i++) {
    if (ds_ctrtNo.getCellData(i, "ctrtClntNo") == cust) {
      hasData = true;
      break;
    }
  }
  return hasData;
};
scwin.updateCtrnNoFilter = function (cust) {
  scwin.selectedCust = cust;
  lds_ctrtNo.clearFilter(); //필터링 해제
  lds_ctrtNo.setColumnFilter({
    type: 'func',
    colIndex: 'ctrtClntNo',
    key: scwin.lds_ctrtNoFilterFunc,
    condition: 'and'
  });
};
scwin.lds_ctrtNoFilterFunc = function (cellData, tmpParam, rowIdx) {
  if (cellData == scwin.selectedCust) {
    return true;
  }
  return false; //return이 true인 경우 적용하고 false인 경우 skip한다.
};
