    gr_BulkTariff.setCellReadOnly(rowIndex, "curr", false);
    gr_BulkTariff.setCellReadOnly(rowIndex, "contractno", false);
    gr_BulkTariff.setCellReadOnly(rowIndex, "apdtFrom", false);
    gr_BulkTariff.setCellReadOnly(rowIndex, "apdtTo", false);
